// ── UUID + migration ─────────────────────────────────────────
function _uuid() {
  if (window.crypto && crypto.randomUUID) return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

function _migrateLocalJobs() {
  try {
    var jobs = JSON.parse(localStorage.getItem('tbd_jobs') || '[]');
    var changed = false;
    jobs.forEach(function(j) {
      if (!j.id) { j.id = _uuid(); changed = true; }
      if (!j.saved_at) { j.saved_at = j.date || new Date().toISOString(); changed = true; }
    });
    if (changed) _saveJobsLocal(jobs);
  } catch(e) {}
}

// PDF saver with iOS in-app webview fallback.
// Safari-in-Facebook / Instagram blocks direct downloads — open in new tab so user can share from preview.
function _pdfSave(doc, fn) {
  try {
    var ua = navigator.userAgent || '';
    var inApp = /FBAN|FBAV|Instagram|Line\/|Twitter|MicroMessenger|LinkedInApp/i.test(ua);
    if (inApp) {
      try {
        var url = doc.output('bloburl');
        window.open(url, '_blank');
        return;
      } catch(e) {
        // fall through to save
      }
    }
    doc.save(fn);
  } catch(e) {
    try {
      var durl = doc.output('datauristring');
      var w = window.open();
      if (w) { w.document.write('<iframe src="' + durl + '" style="width:100%;height:100%;border:0" frameborder="0"></iframe>'); }
    } catch(_) {}
  }
}

// Quota-aware saver — on QuotaExceededError, trims oldest unsynced jobs until fits.
// Protects synced jobs first, gives up gracefully with a toast if truly full.
function _saveJobsLocal(jobs) {
  try {
    localStorage.setItem('tbd_jobs', JSON.stringify(jobs));
    return true;
  } catch(e) {
    if (e && (e.name === 'QuotaExceededError' || e.code === 22 || /quota/i.test(e.message || ''))) {
      // Sort oldest-first, prefer dropping already-synced (cloud-safe) jobs
      var sorted = jobs.slice().sort(function(a, b) {
        var sa = a.pending_sync ? 1 : 0, sb = b.pending_sync ? 1 : 0;
        if (sa !== sb) return sa - sb; // synced first => drop first
        return (a.saved_at || '').localeCompare(b.saved_at || '');
      });
      while (sorted.length > 1) {
        sorted.shift();
        try {
          localStorage.setItem('tbd_jobs', JSON.stringify(sorted));
          if (typeof pwaToast === 'function') pwaToast('Storage full — older synced jobs trimmed.');
          return true;
        } catch(e2) { /* keep shrinking */ }
      }
      try { if (typeof pwaToast === 'function') pwaToast('Storage full — save failed. Export a quote to free space.'); } catch(_) {}
      return false;
    }
    return false;
  }
}

// ── Auth UI helpers ─────────────────────────────────────────
var _authPendingSave = false;

function _authTab(tab) {
  var isLogin = tab === 'login';
  document.getElementById('authTabLogin').style.color = isLogin ? '#E8461E' : '#aaa';
  document.getElementById('authTabLogin').style.borderBottom = isLogin ? '2px solid #E8461E' : 'none';
  document.getElementById('authTabRegister').style.color = isLogin ? '#aaa' : '#E8461E';
  document.getElementById('authTabRegister').style.borderBottom = isLogin ? 'none' : '2px solid #E8461E';
  document.getElementById('authSubmitBtn').textContent = isLogin ? 'Login' : 'Register';
  document.getElementById('authError').style.display = 'none';
  document.getElementById('authTabLogin').dataset.active = isLogin ? '1' : '';
  document.getElementById('authTabRegister').dataset.active = isLogin ? '' : '1';
}

function _authModalOpen(fromSave) {
  _authPendingSave = !!fromSave;
  document.getElementById('authSubtitle').textContent = fromSave
    ? 'Login to sync this quote across devices'
    : 'Login to sync your quotes across devices';
  document.getElementById('authError').style.display = 'none';
  document.getElementById('authEmail').value = '';
  document.getElementById('authPassword').value = '';
  _authTab('login');
  document.getElementById('authModal').classList.add('open');
}

function _authModalClose() {
  document.getElementById('authModal').classList.remove('open');
  _authPendingSave = false;
}

function _authSaveLocal() {
  var wasPending = _authPendingSave;
  _authModalClose();
  if (wasPending) _doLocalSave();
}

function _authShowError(msg) {
  var el = document.getElementById('authError');
  el.textContent = msg;
  el.style.display = 'block';
}

async function _authSubmit() {
  var email = (document.getElementById('authEmail').value || '').trim().toLowerCase();
  var password = document.getElementById('authPassword').value || '';
  var isRegister = !!document.getElementById('authTabRegister').dataset.active;

  if (!email || !password) { _authShowError('Email and password required.'); return; }

  // Client-side convenience gate only — real enforcement MUST live in Supabase
  // (e.g. a Postgres trigger on auth.users that rejects non-@totalblindd.co.za inserts,
  // or a custom auth hook). Anyone can bypass this JS check via devtools.
  if (isRegister && !email.endsWith('@totalblindd.co.za')) {
    _authShowError('Registration is restricted to @totalblindd.co.za email addresses.');
    return;
  }

  var btn = document.getElementById('authSubmitBtn');
  btn.textContent = isRegister ? 'Creating account\u2026' : 'Logging in\u2026';
  btn.disabled = true;

  try {
    var result = isRegister
      ? await _sb.auth.signUp({ email: email, password: password })
      : await _sb.auth.signInWithPassword({ email: email, password: password });

    if (result.error) {
      var msg = result.error.message;
      if (!isRegister && /invalid login credentials/i.test(msg)) {
        msg = 'Invalid login credentials. If new user, click Register tab first.';
      }
      _authShowError(msg);
      btn.textContent = isRegister ? 'Register' : 'Login';
      btn.disabled = false;
      return;
    }

    // Registration: if no session returned, email confirmation is required
    if (isRegister && !result.data.session) {
      _authShowError('\u2705 Account created. Check email ' + email + ' for confirm link, then login.');
      btn.textContent = 'Register';
      btn.disabled = false;
      return;
    }

    _currentUser = result.data.user;
    var pendingSave = _authPendingSave;
    _authModalClose();
    _updateAuthUI();
    _checkImportPrompt();
    if (pendingSave) {
      pwaConfirmSaveJob();
    }
    pwaToast('\u2705 ' + (isRegister ? 'Registered' : 'Logged in') + ' as ' + email);
    syncQueue();
  } catch(e) {
    _authShowError('Login failed. Check connection.');
    btn.textContent = isRegister ? 'Register' : 'Login';
    btn.disabled = false;
  }
}

async function _authForgot() {
  if (!_sb) { _authShowError('Auth unavailable — check connection.'); return; }
  var email = (document.getElementById('authEmail').value || '').trim();
  if (!email) { _authShowError('Enter your email address first.'); return; }
  try {
    var result = await _sb.auth.resetPasswordForEmail(email);
    if (result.error) { _authShowError(result.error.message); return; }
    pwaToast('\ud83d\udce7 Password reset email sent. Check your inbox.');
    _authModalClose();
  } catch(e) {
    _authShowError('Could not send reset email. Check connection.');
  }
}

async function _authLogout() {
  var jobs = JSON.parse(localStorage.getItem('tbd_jobs') || '[]');
  var pending = jobs.filter(function(j) { return j.pending_sync; }).length;
  if (pending > 0) {
    if (!confirm('You have ' + pending + ' unsynced job(s). Log out anyway? They\'ll sync next time you log in.')) return;
  }
  if (_sb) {
    try { await _sb.auth.signOut(); } catch(e) {}
  }
  _currentUser = null;
  // Clear per-user form state so next user doesn't inherit previous customer data
  try {
    localStorage.removeItem('tbd_autosave');
    ['c_nm','c_pn','c_ad','c_cl','c_em','c_tl','c_re','c_md','c_gn',
     'od_c_nm','od_c_pn','od_c_ad','od_c_cl','od_c_em','od_c_tl','od_c_re','od_c_md','od_c_gn',
     'ct_c_nm','ct_c_pn','ct_c_ad','ct_c_cl','ct_c_em','ct_c_tl','ct_c_re','ct_c_md','ct_c_gn']
      .forEach(function(id){var e=document.getElementById(id);if(e)e.value='';});
    if (typeof rows !== 'undefined') { rows = [newRow()]; if (typeof renderAllRows==='function') renderAllRows(); }
    if (typeof od_rows !== 'undefined') { od_rows = []; if (typeof od_renderAllRows==='function') od_renderAllRows(); }
    if (typeof ct_rows !== 'undefined') { ct_rows = []; if (typeof ct_renderAllRows==='function') ct_renderAllRows(); }
    if (typeof updatePrices==='function') updatePrices();
    if (typeof od_updatePrices==='function') od_updatePrices();
    if (typeof ct_updatePrices==='function') ct_updatePrices();
  } catch(e) {}
  _updateAuthUI();
  pwaToast('Logged out.');
}

function _updateAuthUI() {
  var badge = document.getElementById('authBadge');
  var emailEl = document.getElementById('authUserEmail');
  if (!badge) return;
  if (_currentUser) {
    badge.classList.add('visible');
    if (emailEl) emailEl.textContent = _currentUser.email || '';
    _updateSyncBadge();
  } else {
    badge.classList.remove('visible');
  }
}

function _updateSyncBadge() {
  var el = document.getElementById('syncBadge');
  if (!el) return;
  var jobs = JSON.parse(localStorage.getItem('tbd_jobs') || '[]');
  var pending = jobs.filter(function(j) { return j.pending_sync; }).length;
  el.className = 'sync-badge-synced';
  el.textContent = '\u25cf Synced';
  if (!navigator.onLine) {
    el.className = 'sync-badge-offline';
    el.textContent = pending > 0 ? '\u25cf Offline \u2014 ' + pending + ' pending' : '\u25cf Offline';
  } else if (pending > 0) {
    el.className = 'sync-badge-pending';
    el.textContent = '\u27f3 Syncing\u2026';
  }
}

function _doLocalSave() {
  var p = document.getElementById('pwaJobsPanel');
  if (p) p.style.display = 'block';
  var ni = document.getElementById('pwaJobName');
  var nm = (document.getElementById('c_nm') || {}).value || '';
  var pn = (document.getElementById('c_pn') || {}).value || '';
  if (ni) ni.value = nm || pn || '';
}

// Stubs — implemented in later tasks
async function syncQueue() {
  if (!_sb || !_currentUser || !navigator.onLine) return;
  try {
    var jobs = JSON.parse(localStorage.getItem('tbd_jobs') || '[]');
    var pending = jobs.filter(function(j) { return j.pending_sync; });
    if (pending.length === 0) return;

    for (var i = 0; i < pending.length; i++) {
      var job = pending[i];
      try {
        var result = await _sb.from('jobs').upsert({
          id: job.id,
          user_id: _currentUser.id,
          owner_email: _currentUser.email || null,
          label: job.label,
          state: job.state,
          saved_at: job.saved_at || job.date || new Date().toISOString()
        }, { onConflict: 'id' });

        if (!result.error) {
          jobs = JSON.parse(localStorage.getItem('tbd_jobs') || '[]');
          var idx = jobs.findIndex(function(j) { return j.id === job.id; });
          if (idx !== -1) {
            delete jobs[idx].pending_sync;
            _saveJobsLocal(jobs);
          }
        } else {
          pwaToast('⚠️ Auto-sync failed: ' + (result.error.message || 'unknown error'));
        }
      } catch(e) { pwaToast('⚠️ Auto-sync error: ' + (e.message || e)); }
    }
    _updateSyncBadge();
  } catch(e) {}
}
